  ('dietitian-moex-07739', 'dietitian', 'dietitian-moex-100-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '預估食物成本百分比的計算是以預計收入百分比（100%）－其他費用（管理費＋營業量）百分比－利潤 百分比。某團膳公司某日的收入在100萬，利潤有5%，食物成本為25萬元，成本在50%，則其他費用 含管理費和營業量百分比為何？', '["30%", "45%", "50%", "60%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "907fc579dde6", "answer_pdf_sha1": "b16af57e26e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
